#include <stdio.h>
#include <stdlib.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X, N;
        scanf("%lld %lld", &X, &N);
        long long required = (N + 99) / 100; // ceil division
        long long ans = required > X ? required - X : 0;
        printf("%lld\n", ans);
    }
    return 0;
}

